"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Tell us a little about yourself.",
  },
  {
    step: 3,
    title: "Complete",
    description: "Review your information and finish setup.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-lg">
      <Stepper activeStep={activeStep}>
        {/* Step indicators row */}
        <div className="flex items-center">
          {steps.map(({ step, title }) => (
            <StepperItem key={step} step={step}>
              <StepperTrigger
                onClick={() => setActiveStep(step)}
                aria-label={`Go to step ${step}: ${title}`}
              />
              <StepperTitle>{title}</StepperTitle>
              {step < steps.length && <StepperSeparator />}
            </StepperItem>
          ))}
        </div>

        {/* Content panels — only the active step renders */}
        {steps.map(({ step, description }) => (
          <StepperContent key={step} step={step}>
            <div className="rounded-lg border p-6">
              <p className="text-sm text-muted-foreground">{description}</p>
            </div>
          </StepperContent>
        ))}

        {/* Navigation */}
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
            disabled={activeStep === 1}
          >
            Previous
          </Button>
          <Button
            onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
            disabled={activeStep === steps.length}
          >
            Next
          </Button>
        </div>
      </Stepper>
    </div>
  )
}

